634→### 2.5  The Async Job Queue Pattern
635→
636→This pattern is one of the most important in the whole codebase for building
637→responsive, correct UIs over slow I/O.
638→
639→```rust
640→enum GitJob {
641→    RefreshStatus { path_prefixes: Vec<RepoPath> },
642→    StageEntries  { paths: Vec<RepoPath>, tx: oneshot::Sender<Result<()>> },
643→    UnstageEntries{ paths: Vec<RepoPath>, tx: oneshot::Sender<Result<()>> },
644→    SetIndexText  { path: RepoPath, content: Option<String>, tx: oneshot::Sender<Result<()>> },
645→    Commit        { message: String, options: CommitOptions, tx: oneshot::Sender<Result<()>> },
646→    Push          { remote: Option<String>, tx: oneshot::Sender<Result<()>> },
647→    Pull          { rebase: bool, tx: oneshot::Sender<Result<()>> },
648→    Fetch         { tx: oneshot::Sender<Result<()>> },
649→    // ...
650→}
651→```
652→
653→**Queue construction in `Repository::new()`:**
654→
655→```rust
656→let (job_sender, mut job_receiver) = mpsc::unbounded_channel::<GitJob>();
657→
658→let git_repo_clone = git_repo.clone();
659→let executor = cx.background_executor().clone();
660→let entity = cx.weak_entity();
661→
662→// This task runs for the entire lifetime of the Repository entity.
663→// It serializes all git operations onto a single background thread.
664→let worker_task = cx.background_spawn(async move {
665→    while let Some(job) = job_receiver.next().await {
666→        match job {
667→            GitJob::RefreshStatus { path_prefixes } => {
668→                let result = git_repo_clone.status(&path_prefixes);
669→                entity.update(&mut executor.clone(), |repo, cx| {
670→                    if let Ok(entries) = result {
671→                        repo.statuses = SumTree::from_iter(entries, &());
672→                        cx.notify();   // ← triggers re-render
673→                    }
674→                }).ok();
675→            }
676→            GitJob::StageEntries { paths, tx } => {
677→                let env = build_askpass_env();
678→                let result = git_repo_clone.stage_paths(&paths, &env);
679→                let _ = tx.send(result);
680→                // After staging, always refresh status:
681→                let _ = git_repo_clone.status(&[]);
682→                entity.update(/* update statuses and cx.notify() */).ok();
683→            }
684→            // ... other arms
685→        }
686→    }
687→});
688→// Store the task so it stays alive:
689→self._worker_task = Some(worker_task);
690→```
691→
692→**Key invariants:**
693→- Jobs are processed one at a time (single background thread).
694→- Status is always refreshed after any mutating operation.
695→- The `oneshot::Sender<Result<()>>` in each mutating job lets the caller
696→  await the result if needed (e.g. to show an error toast).
697→- `entity.update(...)` safely re-enters the GPUI entity from the background
698→  thread via `WeakEntity::update`.
699→
700→**Submitting a job from the panel:**
701→
702→```rust
703→// In GitPanel, e.g. on_stage_all():
704→self.git_store.update(cx, |store, cx| {
705→    if let Some(repo) = store.active_repository() {
706→        repo.update(cx, |repo, _cx| {
707→            let (tx, rx) = oneshot::channel();
708→            repo.job_sender.send(GitJob::StageEntries {
709→                paths: selected_paths,
710→                tx,
711→            }).ok();
712→            // Optionally await rx in a spawned task for error reporting.
713→        });
714→    }
715→});
716→```
