768→### 2.7  Buffer Diff Lifecycle in `GitStore`
769→
770→```rust
771→fn create_buffer_diffs_for(
772→    &mut self,
773→    buffer: &Entity<Buffer>,
774→    cx: &mut Context<Self>,
775→) {
776→    let buffer_id = buffer.read(cx).remote_id();
777→    let path = buffer.read(cx).file().map(|f| f.path().clone())?;
778→
779→    // Find which repository owns this path.
780→    let (repo_id, repo) = self.repository_for_path(&path, cx)?;
781→    let git_repo = repo.read(cx).git_repo.clone();
782→
783→    // --- Create the UNSTAGED diff (working tree vs. index) ---
784→    let unstaged_diff = cx.new(|cx| {
785→        let index_text = git_repo.index_text_for_path(&repo_path_from(&path)).ok().flatten();
786→        BufferDiff::new(buffer.clone(), index_text, cx)
787→    });
788→
789→    // --- Create the UNCOMMITTED diff (working tree vs. HEAD) ---
790→    let uncommitted_diff = cx.new(|cx| {
791→        let head_text = git_repo.head_text_for_path(&repo_path_from(&path)).ok().flatten();
792→        BufferDiff::new(buffer.clone(), head_text, cx)
793→    });
794→
795→    self.buffer_diffs.insert(buffer_id, (
796→        Some(unstaged_diff),
797→        Some(uncommitted_diff),
798→    ));
799→}
800→```
801→
802→When the index is updated (e.g. after staging), the unstaged diff needs to
803→recompute its base text. `GitStore` handles this by observing staging
804→completion:
805→
806→```rust
807→// In Repository's job worker, after a successful StageEntries:
808→entity.update(cx, |repo, cx| {
809→    cx.emit(RepositoryEvent::IndexChanged);
810→});
811→
812→// In GitStore, subscribed to RepositoryEvent:
813→cx.subscribe(&repo, |this, _, event, cx| {
814→    if matches!(event, RepositoryEvent::IndexChanged) {
815→        this.refresh_unstaged_diffs_for(repo_id, cx);
816→    }
817→});
818→```
