851→    /// Called when git needs a prompt answered.
852→    callback: Box<dyn FnOnce(String, oneshot::Sender<String>)>,
853→}
854→
855→fn create_askpass_env(&mut self, cx: &mut Context<Self>) -> HashMap<String, String> {
856→    let id = self.next_askpass_id;
857→    self.next_askpass_id += 1;
858→
859→    let (prompt_tx, mut prompt_rx) = mpsc::channel(1);
860→    let entity = cx.entity().downgrade();
861→
862→    // The UI registers a delegate that shows a modal:
863→    self.askpass_delegates.insert(id, AskPassDelegate {
864→        callback: Box::new(move |prompt, response_tx| {
865→            entity.update(/* show credential modal, write to response_tx */).ok();
866→        }),
867→    });
868→
869→    let mut env = HashMap::new();
870→    env.insert("GIT_ASKPASS".into(), askpass_binary_path());
871→    env.insert("ZEDASKPASS_DELEGATE_ID".into(), id.to_string());
872→    env.insert("ZEDASKPASS_SOCKET_PATH".into(), socket_path().to_string_lossy().into());
873→    env
874→}
