1026→
1027→pub enum SecondaryHunkStatus {
1028→    /// The hunk does not exist in the secondary diff (fully staged).
1029→    NoSecondaryHunk,
1030→    /// The hunk exists in the secondary diff (fully unstaged).
1031→    HasSecondaryHunk,
1032→    /// The hunk partially overlaps the secondary diff (partially staged).
1033→    OverlapsWithSecondaryHunk,
1034→}
