 71→    pub fn new() -> Self {
 72→        Self {
 73→            entities: SecondaryMap::new(),
 74→            accessed_entities: RefCell::new(FxHashSet::default()),
 75→            ref_counts: Arc::new(RwLock::new(EntityRefCounts {
