  1→use gpui::{
  2→    div, Context, Entity, FocusHandle, InteractiveElement, IntoElement, ParentElement, Render,
  3→    StatefulInteractiveElement, Styled, Subscription, Window,
  4→};
  5→
  6→use crate::actions::{
  7→    Commit, SelectNext, SelectPrev, StageAll, ToggleStaging, UnstageAll,
  8→};
  9→use crate::git::store::{GitStore, GitStoreEvent};
 10→use crate::git::types::{CommitOptions, FileStatus, RepoPath, StagingState, StatusEntry};
 11→use crate::theme::Theme;
 12→
 13→// ---------------------------------------------------------------------------
 14→// Entry — a file in the staged or unstaged section
 15→// ---------------------------------------------------------------------------
 16→
 17→#[derive(Clone, Debug)]
 18→struct PanelEntry {
 19→    status_entry: StatusEntry,
 20→    staged: bool,
 21→}
 22→
 23→// ---------------------------------------------------------------------------
 24→// GitPanel
 25→// ---------------------------------------------------------------------------
 26→
 27→pub struct GitPanel {
 28→    git_store: Entity<GitStore>,
 29→    entries: Vec<PanelEntry>,
 30→    selected_index: Option<usize>,
 31→    commit_message: String,
 32→    focus_handle: FocusHandle,
 33→    _subscriptions: Vec<Subscription>,
 34→}
 35→
 36→impl GitPanel {
 37→    pub fn new(
 38→        git_store: Entity<GitStore>,
 39→        cx: &mut Context<Self>,
 40→    ) -> Self {
 41→        let focus_handle = cx.focus_handle();
 42→
 43→        let sub = cx.subscribe(&git_store, |this: &mut Self, _store, event, cx| {
 44→            match event {
 45→                GitStoreEvent::StatusesChanged(_)
 46→                | GitStoreEvent::ActiveRepositoryChanged
 47→                | GitStoreEvent::BranchChanged => {
 48→                    this.rebuild_entries(cx);
 49→                    cx.notify();
 50→                }
 51→                GitStoreEvent::CommitCompleted { .. } => {
 52→                    this.commit_message.clear();
 53→                    this.rebuild_entries(cx);
 54→                    cx.notify();
 55→                }
 56→            }
 57→        });
 58→
 59→        let mut panel = Self {
 60→            git_store,
 61→            entries: Vec::new(),
 62→            selected_index: None,
 63→            commit_message: String::new(),
 64→            focus_handle,
 65→            _subscriptions: vec![sub],
 66→        };
 67→
 68→        panel.rebuild_entries(cx);
 69→        panel
 70→    }
 71→
 72→    fn rebuild_entries(&mut self, cx: &mut Context<Self>) {
 73→        self.entries.clear();
 74→
 75→        let store = self.git_store.read(cx);
 76→        let Some(repo_entity) = store.active_repository() else {
 77→            return;
 78→        };
 79→
 80→        let repo = repo_entity.read(cx);
 81→
 82→        for entry in repo.statuses() {
 83→            let effective = repo.effective_staging_state(&entry.repo_path);
 84→            match effective {
 85→                StagingState::Staged => {
 86→                    self.entries.push(PanelEntry {
 87→                        status_entry: entry.clone(),
 88→                        staged: true,
 89→                    });
 90→                }
 91→                StagingState::Unstaged => {
 92→                    self.entries.push(PanelEntry {
 93→                        status_entry: entry.clone(),
 94→                        staged: false,
 95→                    });
 96→                }
 97→                StagingState::PartiallyStaged => {
 98→                    self.entries.push(PanelEntry {
 99→                        status_entry: entry.clone(),
100→                        staged: true,
101→                    });
102→                    self.entries.push(PanelEntry {
103→                        status_entry: entry.clone(),
104→                        staged: false,
105→                    });
106→                }
107→            }
108→        }
109→
110→        // Sort: staged first, then unstaged; within each group, by path
111→        self.entries.sort_by(|a, b| {
112→            b.staged
113→                .cmp(&a.staged)
114→                .then_with(|| a.status_entry.repo_path.cmp(&b.status_entry.repo_path))
115→        });
116→
117→        // Clamp selection
118→        if let Some(idx) = self.selected_index {
119→            if idx >= self.entries.len() {
120→                self.selected_index = if self.entries.is_empty() {
121→                    None
122→                } else {
123→                    Some(self.entries.len() - 1)
124→                };
125→            }
126→        }
127→    }
128→
129→    fn staged_entries(&self) -> Vec<&PanelEntry> {
130→        self.entries.iter().filter(|e| e.staged).collect()
131→    }
132→
133→    fn unstaged_entries(&self) -> Vec<&PanelEntry> {
134→        self.entries.iter().filter(|e| !e.staged).collect()
135→    }
136→
137→    fn toggle_staging_for(
138→        &mut self,
139→        path: RepoPath,
140→        currently_staged: bool,
141→        cx: &mut Context<Self>,
142→    ) {
143→        let store = self.git_store.read(cx);
144→        let Some(repo_entity) = store.active_repository().cloned() else {
145→            return;
146→        };
147→
148→        if currently_staged {
149→            repo_entity.update(cx, |repo, cx| {
150→                repo.unstage(vec![path], cx);
151→            });
152→        } else {
153→            repo_entity.update(cx, |repo, cx| {
154→                repo.stage(vec![path], cx);
155→            });
156→        }
157→    }
158→
159→    fn stage_all(&mut self, cx: &mut Context<Self>) {
160→        let paths: Vec<RepoPath> = self
161→            .unstaged_entries()
162→            .iter()
163→            .map(|e| e.status_entry.repo_path.clone())
164→            .collect();
165→
166→        if paths.is_empty() {
167→            return;
168→        }
169→
170→        let store = self.git_store.read(cx);
171→        let Some(repo_entity) = store.active_repository().cloned() else {
172→            return;
173→        };
174→
175→        repo_entity.update(cx, |repo, cx| {
176→            repo.stage(paths, cx);
177→        });
178→    }
179→
180→    fn unstage_all(&mut self, cx: &mut Context<Self>) {
181→        let paths: Vec<RepoPath> = self
182→            .staged_entries()
183→            .iter()
184→            .map(|e| e.status_entry.repo_path.clone())
185→            .collect();
186→
187→        if paths.is_empty() {
188→            return;
189→        }
190→
191→        let store = self.git_store.read(cx);
192→        let Some(repo_entity) = store.active_repository().cloned() else {
193→            return;
194→        };
195→
196→        repo_entity.update(cx, |repo, cx| {
197→            repo.unstage(paths, cx);
198→        });
199→    }
200→
201→    fn toggle_selected(&mut self, cx: &mut Context<Self>) {
202→        let Some(idx) = self.selected_index else {
203→            return;
204→        };
205→        let Some(entry) = self.entries.get(idx) else {
206→            return;
207→        };
208→        let path = entry.status_entry.repo_path.clone();
209→        let staged = entry.staged;
210→        self.toggle_staging_for(path, staged, cx);
211→    }
212→
213→    fn do_commit(&mut self, cx: &mut Context<Self>) {
214→        let message = self.commit_message.trim().to_string();
215→        if message.is_empty() {
216→            return;
217→        }
218→
219→        let store = self.git_store.read(cx);
220→        let Some(repo_entity) = store.active_repository().cloned() else {
221→            return;
222→        };
223→
224→        repo_entity.update(cx, |repo, cx| {
225→            repo.commit(message, CommitOptions::default(), cx);
226→        });
227→    }
228→
229→    fn select_next(&mut self, cx: &mut Context<Self>) {
230→        if self.entries.is_empty() {
231→            return;
232→        }
233→        self.selected_index = Some(match self.selected_index {
234→            None => 0,
235→            Some(idx) => (idx + 1).min(self.entries.len() - 1),
236→        });
237→        cx.notify();
238→    }
239→
240→    fn select_prev(&mut self, cx: &mut Context<Self>) {
241→        if self.entries.is_empty() {
242→            return;
243→        }
244→        self.selected_index = Some(match self.selected_index {
245→            None => 0,
246→            Some(idx) => idx.saturating_sub(1),
247→        });
248→        cx.notify();
249→    }
250→
251→    fn handle_key_down(
252→        &mut self,
253→        event: &gpui::KeyDownEvent,
254→        _window: &mut Window,
255→        cx: &mut Context<Self>,
256→    ) {
257→        let key_char = event.keystroke.key_char.as_deref();
258→        match key_char {
259→            Some(ch) if !event.keystroke.modifiers.platform
260→                && !event.keystroke.modifiers.control =>
261→            {
262→                self.commit_message.push_str(ch);
263→                cx.notify();
264→            }
265→            _ => {
266→                // Handle special keys by key name
267→                match event.keystroke.key.as_str() {
268→                    "backspace" if !event.keystroke.modifiers.platform => {
269→                        self.commit_message.pop();
270→                        cx.notify();
271→                    }
272→                    _ => {}
273→                }
274→            }
275→        }
276→    }
277→}
278→
279→impl Render for GitPanel {
280→    fn render(&mut self, _window: &mut Window, cx: &mut Context<Self>) -> impl IntoElement {
281→        let theme = cx.global::<Theme>();
282→        let focus_handle = self.focus_handle.clone();
283→
284→        // Read toolbar data
285→        let store = self.git_store.read(cx);
286→        let active_repo = store.active_repository();
287→
288→        let (branch_name, ahead, behind, total_files) = if let Some(repo_entity) = active_repo {
289→            let repo = repo_entity.read(cx);
290→            let snapshot = repo.snapshot();
291→            let name = snapshot
292→                .branch
293→                .as_ref()
294→                .map(|b| b.name.clone())
295→                .unwrap_or_else(|| "detached".to_string());
296→            let (a, b) = snapshot
297→                .branch
298→                .as_ref()
299→                .and_then(|br| br.upstream.as_ref())
300→                .map(|u| (u.ahead.unwrap_or(0), u.behind.unwrap_or(0)))
301→                .unwrap_or((0, 0));
302→            let total = repo.statuses().len();
303→            (name, a, b, total)
304→        } else {
305→            ("No repository".to_string(), 0, 0, 0)
306→        };
307→
308→        let staged = self.staged_entries();
309→        let unstaged = self.unstaged_entries();
310→        let staged_count = staged.len();
311→        let unstaged_count = unstaged.len();
312→
313→        // Build toolbar
314→        let mut toolbar = div()
315→            .w_full()
316→            .px_2()
317→            .py_1()
318→            .bg(theme.surface)
319→            .border_b_1()
320→            .border_color(theme.border)
321→            .flex()
322→            .flex_row()
323→            .items_center()
324→            .gap_2()
325→            .child(
326→                div()
327→                    .text_color(theme.text_primary)
328→                    .child(branch_name),
329→            );
330→
331→        if ahead > 0 {
332→            toolbar = toolbar.child(
333→                div()
334→                    .text_color(theme.accent)
335→                    .child(format!("↑{ahead}")),
336→            );
337→        }
338→        if behind > 0 {
339→            toolbar = toolbar.child(
340→                div()
341→                    .text_color(theme.text_muted)
342→                    .child(format!("↓{behind}")),
343→            );
344→        }
345→
346→        toolbar = toolbar.child(
347→            div()
348→                .flex_grow()
349→                .text_color(theme.text_muted)
350→                .flex()
351→                .justify_end()
352→                .child(format!(
353→                    "{} file{}",
354→                    total_files,
355→                    if total_files == 1 { "" } else { "s" }
356→                )),
357→        );
358→
359→        // Build staged section
360→        let mut staged_section = div().w_full().flex().flex_col();
361→
362→        if staged_count > 0 {
363→            staged_section = staged_section.child(
364→                div()
365→                    .px_2()
366→                    .py_1()
367→                    .text_color(theme.text_muted)
368→                    .child(format!("Staged Changes ({staged_count})")),
369→            );
370→
371→            // Find where staged entries start in self.entries
372→            for (global_idx, entry) in self.entries.iter().enumerate() {
373→                if !entry.staged {
374→                    continue;
375→                }
376→                let path = entry.status_entry.repo_path.clone();
377→                let status_char = status_indicator(
378→                    &entry.status_entry,
379→                    entry.staged,
380→                );
381→                let status_color = status_color(
382→                    &entry.status_entry,
383→                    entry.staged,
384→                    theme,
385→                );
386→                let is_selected = self.selected_index == Some(global_idx);
387→
388→                let mut row = div()
389→                    .id(global_idx)
390→                    .px_2()
391→                    .py_px()
392→                    .w_full()
393→                    .flex()
394→                    .flex_row()
395→                    .gap_2()
396→                    .cursor_pointer()
397→                    .child(
398→                        div()
399→                            .text_color(status_color)
400→                            .min_w_4()
401→                            .child(status_char),
402→                    )
403→                    .child(
404→                        div()
405→                            .text_color(theme.text_primary)
406→                            .child(path.to_string()),
407→                    );
408→
409→                if is_selected {
410→                    row = row.bg(theme.surface);
411→                }
412→
413→                let click_path = entry.status_entry.repo_path.clone();
414→                row = row.on_click(
415→                    cx.listener(move |this, _event, _window, cx| {
416→                        let p = click_path.clone();
417→                        this.toggle_staging_for(p, true, cx);
418→                    }),
419→                );
420→
421→                staged_section = staged_section.child(row);
422→            }
423→        }
424→
425→        // Build unstaged section
426→        let mut unstaged_section = div().w_full().flex().flex_col();
427→
428→        if unstaged_count > 0 {
429→            unstaged_section = unstaged_section.child(
430→                div()
431→                    .px_2()
432→                    .py_1()
433→                    .text_color(theme.text_muted)
434→                    .child(format!("Unstaged Changes ({unstaged_count})")),
435→            );
436→
437→            for (global_idx, entry) in self.entries.iter().enumerate() {
438→                if entry.staged {
439→                    continue;
440→                }
441→                let path = entry.status_entry.repo_path.clone();
442→                let status_char = status_indicator(
443→                    &entry.status_entry,
444→                    entry.staged,
445→                );
446→                let status_color = status_color(
447→                    &entry.status_entry,
448→                    entry.staged,
449→                    theme,
450→                );
451→                let is_selected = self.selected_index == Some(global_idx);
452→
453→                let mut row = div()
454→                    .id(global_idx)
455→                    .px_2()
456→                    .py_px()
457→                    .w_full()
458→                    .flex()
459→                    .flex_row()
460→                    .gap_2()
461→                    .cursor_pointer()
462→                    .child(
463→                        div()
464→                            .text_color(status_color)
465→                            .min_w_4()
466→                            .child(status_char),
467→                    )
468→                    .child(
469→                        div()
470→                            .text_color(theme.text_primary)
471→                            .child(path.to_string()),
472→                    );
473→
474→                if is_selected {
475→                    row = row.bg(theme.surface);
476→                }
477→
478→                let click_path = entry.status_entry.repo_path.clone();
479→                row = row.on_click(
480→                    cx.listener(move |this, _event, _window, cx| {
481→                        let p = click_path.clone();
482→                        this.toggle_staging_for(p, false, cx);
483→                    }),
484→                );
485→
486→                unstaged_section = unstaged_section.child(row);
487→            }
488→        }
489→
490→        // Build commit area
491→        let commit_placeholder = if self.commit_message.is_empty() {
492→            "Commit message..."
493→        } else {
494→            ""
495→        };
496→
497→        let commit_display = if self.commit_message.is_empty() {
498→            commit_placeholder.to_string()
499→        } else {
500→            self.commit_message.clone()
501→        };
502→
503→        let commit_text_color = if self.commit_message.is_empty() {
504→            theme.text_muted
505→        } else {
506→            theme.text_primary
507→        };
508→
509→        let has_message = !self.commit_message.trim().is_empty();
510→
511→        let commit_area = div()
512→            .w_full()
513→            .border_t_1()
514→            .border_color(theme.border)
515→            .flex()
516→            .flex_col()
517→            .gap_1()
518→            .p_2()
519→            .child(
520→                div()
521→                    .px_2()
522→                    .py_1()
523→                    .bg(theme.surface)
524→                    .border_1()
525→                    .border_color(theme.border)
526→                    .rounded_sm()
527→                    .text_color(commit_text_color)
528→                    .child(commit_display),
529→            )
530→            .child(
531→                div()
532→                    .id("commit-button")
533→                    .px_2()
534→                    .py_1()
535→                    .bg(if has_message {
536→                        theme.accent
537→                    } else {
538→                        theme.surface
539→                    })
540→                    .rounded_sm()
541→                    .text_color(if has_message {
542→                        theme.background
543→                    } else {
544→                        theme.text_muted
545→                    })
546→                    .cursor_pointer()
547→                    .flex()
548→                    .justify_center()
549→                    .child("Commit")
550→                    .on_click(cx.listener(|this, _event, _window, cx| {
551→                        this.do_commit(cx);
552→                    })),
553→            );
554→
555→        // Assemble
556→        div()
557→            .key_context("git_panel")
558→            .track_focus(&focus_handle)
559→            .on_action(cx.listener(|this, _: &ToggleStaging, _window, cx| {
560→                this.toggle_selected(cx);
561→            }))
562→            .on_action(cx.listener(|this, _: &StageAll, _window, cx| {
563→                this.stage_all(cx);
564→            }))
