595→fn status_indicator(entry: &StatusEntry, staged: bool) -> &'static str {
596→    if staged {
597→        match entry.status.index_status {
598→            FileStatus::Added => "A",
599→            FileStatus::Modified => "M",
600→            FileStatus::Deleted => "D",
601→            FileStatus::Untracked => "?",
602→            FileStatus::Unchanged => " ",
603→        }
604→    } else {
605→        match entry.status.worktree_status {
606→            FileStatus::Added => "A",
607→            FileStatus::Modified => "M",
608→            FileStatus::Deleted => "D",
609→            FileStatus::Untracked => "?",
610→            FileStatus::Unchanged => " ",
611→        }
612→    }
613→}
614→
615→fn status_color(entry: &StatusEntry, staged: bool, theme: &Theme) -> gpui::Hsla {
616→    let file_status = if staged {
617→        entry.status.index_status
618→    } else {
619→        entry.status.worktree_status
620→    };
621→
622→    match file_status {
623→        FileStatus::Added | FileStatus::Untracked => theme.added,
624→        FileStatus::Modified => theme.modified,
625→        FileStatus::Deleted => theme.deleted,
626→        FileStatus::Unchanged => theme.text_muted,
627→    }
628→}
