  1→use std::ops::Range;
  2→
  3→// ---------------------------------------------------------------------------
  4→// SecondaryHunkStatus — staging awareness for diff hunks
  5→// ---------------------------------------------------------------------------
  6→
  7→#[derive(Clone, Copy, Debug, PartialEq, Eq)]
  8→pub enum SecondaryHunkStatus {
  9→    /// Hunk does not exist in the secondary diff — fully staged.
 10→    NoSecondaryHunk,
 11→    /// Hunk exists identically in the secondary diff — fully unstaged.
 12→    HasSecondaryHunk,
 13→    /// Hunk partially overlaps the secondary diff — partially staged.
 14→    OverlapsWithSecondaryHunk,
 15→}
 16→
 17→impl Default for SecondaryHunkStatus {
 18→    fn default() -> Self {
 19→        Self::HasSecondaryHunk
 20→    }
 21→}
 22→
 23→// ---------------------------------------------------------------------------
 24→// DiffHunk
 25→// ---------------------------------------------------------------------------
 26→
 27→#[derive(Clone, Debug, PartialEq, Eq)]
 28→pub struct DiffHunk {
 29→    /// Line range in the current buffer (0-based).
 30→    pub buffer_range: Range<u32>,
 31→    /// Byte range in `base_text` that this hunk replaces.
 32→    pub diff_base_byte_range: Range<usize>,
 33→    /// Staging status relative to a secondary diff.
 34→    pub secondary_status: SecondaryHunkStatus,
 35→}
 36→
 37→// ---------------------------------------------------------------------------
 38→// BufferDiffSnapshot — cheap-to-clone value type
 39→// ---------------------------------------------------------------------------
 40→
 41→#[derive(Clone, Debug, Default)]
 42→pub struct BufferDiffSnapshot {
 43→    pub hunks: Vec<DiffHunk>,
 44→    pub base_text: Option<String>,
 45→}
 46→
 47→impl BufferDiffSnapshot {
 48→    pub fn new(base_text: Option<String>) -> Self {
 49→        Self {
 50→            hunks: Vec::new(),
 51→            base_text,
 52→        }
 53→    }
 54→
 55→    pub fn is_empty(&self) -> bool {
 56→        self.hunks.is_empty()
 57→    }
 58→
 59→    pub fn hunk_count(&self) -> usize {
 60→        self.hunks.len()
 61→    }
 62→
 63→    /// Return hunks whose buffer_range intersects the given line range.
 64→    pub fn hunks_intersecting_range(&self, range: Range<u32>) -> Vec<&DiffHunk> {
 65→        self.hunks
 66→            .iter()
 67→            .filter(|h| ranges_overlap(&h.buffer_range, &range))
 68→            .collect()
 69→    }
 70→}
 71→
 72→// ---------------------------------------------------------------------------
 73→// Diff computation using imara-diff
 74→// ---------------------------------------------------------------------------
 75→
 76→/// Compute diff hunks between base and current text using imara-diff.
 77→pub fn compute_diff_hunks(current: &str, base: Option<&str>) -> Vec<DiffHunk> {
 78→    let base = match base {
 79→        Some(b) => b,
 80→        None => return vec![],
 81→    };
 82→
 83→    if base == current {
 84→        return vec![];
 85→    }
 86→
 87→    let input = imara_diff::intern::InternedInput::new(base, current);
 88→    let sink = HunkCollector {
 89→        hunks: Vec::new(),
 90→        base_text: base,
 91→    };
 92→
 93→    imara_diff::diff(imara_diff::Algorithm::Histogram, &input, sink)
 94→}
 95→
 96→struct HunkCollector<'a> {
 97→    hunks: Vec<DiffHunk>,
 98→    base_text: &'a str,
 99→}
100→
101→impl imara_diff::Sink for HunkCollector<'_> {
102→    type Out = Vec<DiffHunk>;
103→
104→    fn process_change(&mut self, before: Range<u32>, after: Range<u32>) {
105→        let base_byte_start = line_to_byte_offset(self.base_text, before.start as usize);
106→        let base_byte_end = line_to_byte_offset(self.base_text, before.end as usize);
107→
108→        self.hunks.push(DiffHunk {
109→            buffer_range: after,
110→            diff_base_byte_range: base_byte_start..base_byte_end,
111→            secondary_status: SecondaryHunkStatus::default(),
112→        });
113→    }
114→
115→    fn finish(self) -> Self::Out {
116→        self.hunks
117→    }
118→}
119→
120→/// Convert a line number (0-based) to a byte offset in the text.
121→fn line_to_byte_offset(text: &str, line: usize) -> usize {
122→    let mut current_line = 0;
123→    for (i, c) in text.char_indices() {
124→        if current_line == line {
125→            return i;
126→        }
127→        if c == '\n' {
128→            current_line += 1;
129→        }
130→    }
131→    text.len()
132→}
133→
134→// ---------------------------------------------------------------------------
135→// Secondary status computation
136→// ---------------------------------------------------------------------------
137→
138→/// Compare a hunk's buffer range against secondary diff hunks to determine
139→/// staging status.
140→pub fn compute_secondary_status(
141→    hunk: &DiffHunk,
142→    secondary_hunks: &[DiffHunk],
143→) -> SecondaryHunkStatus {
144→    let overlapping: Vec<_> = secondary_hunks
145→        .iter()
146→        .filter(|h| ranges_overlap(&h.buffer_range, &hunk.buffer_range))
147→        .collect();
148→
149→    if overlapping.is_empty() {
150→        // Change is in index but not in HEAD → fully staged
151→        SecondaryHunkStatus::NoSecondaryHunk
152→    } else if overlapping
153→        .iter()
154→        .all(|h| h.buffer_range == hunk.buffer_range)
155→    {
156→        // Change exists in both diffs identically → fully unstaged
157→        SecondaryHunkStatus::HasSecondaryHunk
158→    } else {
159→        // Partial overlap → partially staged
160→        SecondaryHunkStatus::OverlapsWithSecondaryHunk
161→    }
162→}
163→
164→/// Annotate hunks with secondary status computed against another set of hunks.
165→pub fn annotate_hunks_with_secondary(
166→    hunks: &mut [DiffHunk],
167→    secondary_hunks: &[DiffHunk],
168→) {
169→    for hunk in hunks.iter_mut() {
170→        hunk.secondary_status = compute_secondary_status(hunk, secondary_hunks);
171→    }
172→}
173→
174→fn ranges_overlap(a: &Range<u32>, b: &Range<u32>) -> bool {
175→    a.start < b.end && b.start < a.end
176→}
