  6→// ---------------------------------------------------------------------------
  7→// RepoPath — a path relative to the repository root
  8→// ---------------------------------------------------------------------------
  9→
 10→#[derive(Clone, Debug, PartialEq, Eq, Hash)]
 11→pub struct RepoPath(Arc<Path>);
 12→
 13→impl RepoPath {
 14→    pub fn new(path: impl Into<PathBuf>) -> Self {
 15→        Self(Arc::from(path.into()))
 16→    }
 17→
 18→    pub fn as_path(&self) -> &Path {
 19→        &self.0
 20→    }
 21→}
 22→
 23→impl PartialOrd for RepoPath {
 24→    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
 25→        Some(self.cmp(other))
 26→    }
 27→}
 28→
 29→impl Ord for RepoPath {
 30→    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
 31→        self.0.cmp(&other.0)
 32→    }
 33→}
 34→
 35→impl fmt::Display for RepoPath {
 36→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 37→        write!(f, "{}", self.0.display())
 38→    }
 39→}
 40→
 41→impl From<&str> for RepoPath {
 42→    fn from(s: &str) -> Self {
 43→        Self::new(PathBuf::from(s))
 44→    }
 45→}
 46→
 47→impl From<PathBuf> for RepoPath {
 48→    fn from(p: PathBuf) -> Self {
 49→        Self::new(p)
 50→    }
 51→}
 52→
 53→impl From<&Path> for RepoPath {
 54→    fn from(p: &Path) -> Self {
 55→        Self::new(p.to_path_buf())
 56→    }
 57→}
