  1→use std::collections::HashMap;
  2→use std::sync::Arc;
  3→
  4→use gpui::{AppContext, Context, Entity, EventEmitter, Subscription};
  5→
  6→use crate::git::repository::GitRepository;
  7→use crate::git::repo_entity::{Repository, RepositoryEvent};
  8→
  9→// ---------------------------------------------------------------------------
 10→// RepositoryId
 11→// ---------------------------------------------------------------------------
 12→
 13→#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
 14→pub struct RepositoryId(u64);
 15→
 16→// ---------------------------------------------------------------------------
 17→// GitStoreEvent
 18→// ---------------------------------------------------------------------------
 19→
 20→#[derive(Clone, Debug)]
 21→pub enum GitStoreEvent {
 22→    ActiveRepositoryChanged,
 23→    StatusesChanged(RepositoryId),
 24→    CommitCompleted {
 25→        repository_id: RepositoryId,
 26→        was_amend: bool,
 27→    },
 28→    BranchChanged,
 29→}
 30→
 31→// ---------------------------------------------------------------------------
 32→// GitStore
 33→// ---------------------------------------------------------------------------
 34→
 35→pub struct GitStore {
 36→    repositories: HashMap<RepositoryId, Entity<Repository>>,
 37→    active_repository: Option<RepositoryId>,
 38→    next_repository_id: u64,
 39→    _subscriptions: Vec<Subscription>,
 40→}
 41→
 42→impl EventEmitter<GitStoreEvent> for GitStore {}
 43→
 44→impl GitStore {
 45→    pub fn new(_cx: &mut Context<Self>) -> Self {
 46→        Self {
 47→            repositories: HashMap::new(),
 48→            active_repository: None,
 49→            next_repository_id: 0,
 50→            _subscriptions: Vec::new(),
 51→        }
 52→    }
 53→
 54→    /// Add a repository to the store. Returns its ID.
 55→    /// Sets it as active if it's the first repository.
 56→    pub fn add_repository(
 57→        &mut self,
 58→        git_repo: Arc<dyn GitRepository>,
 59→        cx: &mut Context<Self>,
 60→    ) -> RepositoryId {
 61→        let id = RepositoryId(self.next_repository_id);
 62→        self.next_repository_id += 1;
 63→
 64→        let repo_entity = cx.new(|cx| Repository::new(git_repo, cx));
 65→
 66→        // Observe the Repository entity: when it notifies, re-emit
 67→        // StatusesChanged so the panel can react.
 68→        let observe_sub = cx.observe(&repo_entity, {
 69→            move |_this: &mut Self, _repo: Entity<Repository>, cx| {
 70→                cx.emit(GitStoreEvent::StatusesChanged(id));
 71→            }
 72→        });
 73→
 74→        // Subscribe to RepositoryEvent for commit/branch changes.
 75→        let event_sub = cx.subscribe(&repo_entity, {
 76→            move |_this: &mut Self, _repo: Entity<Repository>, event: &RepositoryEvent, cx| {
 77→                match event {
 78→                    RepositoryEvent::StatusChanged => {
 79→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 80→                    }
 81→                    RepositoryEvent::IndexChanged => {
 82→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 83→                    }
 84→                    RepositoryEvent::CommitCompleted { was_amend } => {
 85→                        cx.emit(GitStoreEvent::CommitCompleted {
 86→                            repository_id: id,
 87→                            was_amend: *was_amend,
 88→                        });
 89→                    }
 90→                    RepositoryEvent::BranchChanged => {
 91→                        cx.emit(GitStoreEvent::BranchChanged);
 92→                    }
 93→                }
 94→            }
 95→        });
 96→
 97→        self._subscriptions.push(observe_sub);
 98→        self._subscriptions.push(event_sub);
 99→        self.repositories.insert(id, repo_entity);
100→
101→        // First repository becomes active
102→        if self.active_repository.is_none() {
103→            self.active_repository = Some(id);
104→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
105→        }
106→
107→        id
108→    }
109→
110→    /// Remove a repository from the store.
111→    pub fn remove_repository(
112→        &mut self,
113→        id: RepositoryId,
114→        cx: &mut Context<Self>,
115→    ) {
116→        self.repositories.remove(&id);
117→
118→        if self.active_repository == Some(id) {
119→            // Pick another repository or None
120→            self.active_repository = self.repositories.keys().next().copied();
121→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
122→        }
123→    }
124→
125→    /// Get the active repository entity.
126→    pub fn active_repository(&self) -> Option<&Entity<Repository>> {
127→        self.active_repository
128→            .and_then(|id| self.repositories.get(&id))
129→    }
130→
131→    /// Get the active repository ID.
132→    pub fn active_repository_id(&self) -> Option<RepositoryId> {
133→        self.active_repository
134→    }
135→
136→    /// Set the active repository by ID.
137→    pub fn set_active_repository(
138→        &mut self,
139→        id: RepositoryId,
140→        cx: &mut Context<Self>,
141→    ) {
142→        if self.repositories.contains_key(&id) && self.active_repository != Some(id) {
143→            self.active_repository = Some(id);
144→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
145→        }
146→    }
147→
148→    /// Get a repository by ID.
149→    pub fn repository(&self, id: RepositoryId) -> Option<&Entity<Repository>> {
150→        self.repositories.get(&id)
151→    }
152→
153→    /// Iterate all repositories.
154→    pub fn repositories(
155→        &self,
156→    ) -> impl Iterator<Item = (RepositoryId, &Entity<Repository>)> {
157→        self.repositories.iter().map(|(id, repo)| (*id, repo))
158→    }
159→
160→    /// Number of tracked repositories.
161→    pub fn repository_count(&self) -> usize {
162→        self.repositories.len()
163→    }
164→}
