 10→/// Synchronous, Send + Sync trait for all git operations.
 11→///
 12→/// Implementations wrap either git2 (for local operations) or the git CLI
 13→/// (for network operations). The async wrapper lives in the Repository entity,
 14→/// not here.
 15→pub trait GitRepository: Send + Sync {
 16→    // ── Identity ───────────────────────────────────────────
 17→    fn path(&self) -> &Path;
 18→    fn work_directory(&self) -> Option<&Path>;
 19→
 20→    // ── Staging / Index ────────────────────────────────────
 21→    fn stage_paths(
 22→        &self,
 23→        paths: &[RepoPath],
 24→        env: &HashMap<String, String>,
 25→    ) -> GitResult<()>;
 26→
 27→    fn unstage_paths(
 28→        &self,
 29→        paths: &[RepoPath],
 30→        env: &HashMap<String, String>,
 31→    ) -> GitResult<()>;
 32→
 33→    fn set_index_text(
 34→        &self,
 35→        path: &RepoPath,
 36→        content: Option<String>,
 37→        env: &HashMap<String, String>,
 38→    ) -> GitResult<()>;
 39→
 40→    fn reload_index(&self);
 41→
 42→    // ── Commit ─────────────────────────────────────────────
 43→    fn commit(
 44→        &self,
 45→        message: &str,
 46→        options: &CommitOptions,
 47→        env: &HashMap<String, String>,
 48→    ) -> GitResult<()>;
 49→
 50→    fn uncommit(&self, env: &HashMap<String, String>) -> GitResult<()>;
 51→
 52→    // ── Remote operations ──────────────────────────────────
 53→    fn push(
 54→        &self,
 55→        branch: &str,
 56→        remote: Option<&str>,
 57→        options: &PushOptions,
 58→        env: &HashMap<String, String>,
 59→    ) -> GitResult<()>;
 60→
 61→    fn pull(
 62→        &self,
 63→        rebase: bool,
 64→        env: &HashMap<String, String>,
 65→    ) -> GitResult<()>;
 66→
 67→    fn fetch(&self, env: &HashMap<String, String>) -> GitResult<()>;
 68→
 69→    fn create_remote(&self, name: &str, url: &str) -> GitResult<()>;
 70→
 71→    // ── Status ─────────────────────────────────────────────
 72→    fn status(&self, path_prefixes: &[RepoPath]) -> GitResult<Vec<StatusEntry>>;
 73→    fn status_for_path(&self, path: &RepoPath) -> GitResult<Option<StatusEntry>>;
 74→
 75→    // ── Branch operations ──────────────────────────────────
 76→    fn current_branch(&self) -> Option<Branch>;
 77→    fn branches(&self) -> GitResult<Vec<Branch>>;
 78→    fn create_branch(&self, name: &str) -> GitResult<()>;
 79→    fn checkout(&self, target: &str, env: &HashMap<String, String>) -> GitResult<()>;
 80→    fn delete_branch(&self, name: &str) -> GitResult<()>;
 81→    fn merge_base(&self, a: &str, b: &str) -> GitResult<Option<String>>;
 82→    fn remote_url(&self, name: &str) -> Option<String>;
 83→
 84→    // ── Diff / Content ─────────────────────────────────────
 85→    fn head_text_for_path(&self, path: &RepoPath) -> GitResult<Option<String>>;
 86→    fn index_text_for_path(&self, path: &RepoPath) -> GitResult<Option<String>>;
 87→
 88→    // ── Blame ──────────────────────────────────────────────
 89→    fn blame_for_path(
 90→        &self,
 91→        path: &RepoPath,
 92→        content: &str,
 93→    ) -> GitResult<Vec<BlameEntry>>;
 94→
 95→    // ── Stash ──────────────────────────────────────────────
 96→    fn stash_list(&self) -> GitResult<Vec<StashEntry>>;
 97→    fn stash_all(&self, message: Option<&str>) -> GitResult<()>;
 98→    fn stash_pop(&self, index: usize) -> GitResult<()>;
 99→    fn stash_apply(&self, index: usize) -> GitResult<()>;
100→    fn stash_drop(&self, index: usize) -> GitResult<()>;
101→
102→    // ── History ────────────────────────────────────────────
103→    fn log(
104→        &self,
105→        path: Option<&RepoPath>,
106→        limit: usize,
107→    ) -> GitResult<Vec<CommitSummary>>;
108→
109→    fn show(&self, oid: &str) -> GitResult<CommitDetails>;
110→
111→    // ── Conflict resolution ────────────────────────────────
112→    fn checkout_conflict_path(
113→        &self,
114→        path: &RepoPath,
115→        side: ConflictSide,
116→    ) -> GitResult<()>;
117→}
