323→            unix_timestamp: None,
324→        })
325→    }
326→
327→    fn branches(&self) -> GitResult<Vec<Branch>> {
328→        Ok(self.branches.lock().unwrap().clone())
329→    }
330→
331→    fn create_branch(&self, name: &str) -> GitResult<()> {
332→        self.branches.lock().unwrap().push(Branch {
