107→impl GitRepository for RealGitRepository {
108→    // ── Identity ───────────────────────────────────────────
109→
110→    fn path(&self) -> &Path {
111→        &self.path
112→    }
113→
114→    fn work_directory(&self) -> Option<&Path> {
115→        self.work_directory.as_deref()
116→    }
117→
118→    // ── Status ─────────────────────────────────────────────
119→
120→    fn status(&self, path_prefixes: &[RepoPath]) -> GitResult<Vec<StatusEntry>> {
121→        let repo = self.repository.lock().unwrap();
122→        let mut opts = git2::StatusOptions::new();
123→        opts.include_untracked(true)
124→            .recurse_untracked_dirs(true)
125→            .include_unmodified(false);
126→
127→        for prefix in path_prefixes {
128→            opts.pathspec(prefix.as_path());
129→        }
130→
131→        let statuses = repo.statuses(Some(&mut opts))?;
132→        let mut entries = Vec::with_capacity(statuses.len());
133→
134→        for entry in statuses.iter() {
135→            if let Some(path) = entry.path() {
136→                let status = Self::map_git2_status(entry.status());
137→                entries.push(StatusEntry {
138→                    repo_path: RepoPath::from(path),
139→                    status,
140→                });
141→            }
142→        }
143→
144→        entries.sort_by(|a, b| a.repo_path.cmp(&b.repo_path));
145→        Ok(entries)
146→    }
147→
148→    fn status_for_path(&self, path: &RepoPath) -> GitResult<Option<StatusEntry>> {
149→        let repo = self.repository.lock().unwrap();
150→        match repo.status_file(path.as_path()) {
151→            Ok(status) => {
152→                if status.is_empty() {
153→                    Ok(None)
154→                } else {
155→                    Ok(Some(StatusEntry {
156→                        repo_path: path.clone(),
157→                        status: Self::map_git2_status(status),
158→                    }))
159→                }
160→            }
161→            Err(e) if e.code() == git2::ErrorCode::NotFound => Ok(None),
162→            Err(e) => Err(e.into()),
163→        }
164→    }
165→
166→    // ── Branch operations ──────────────────────────────────
167→
168→    fn current_branch(&self) -> Option<Branch> {
169→        let repo = self.repository.lock().unwrap();
170→        let head = repo.head().ok()?;
171→        let name = head.shorthand()?.to_string();
172→
173→        let upstream = head
174→            .name()
175→            .and_then(|refname| repo.find_branch(refname.strip_prefix("refs/heads/")?, git2::BranchType::Local).ok())
176→            .and_then(|branch| {
177→                let upstream = branch.upstream().ok()?;
178→                let upstream_name = upstream.name().ok()??.to_string();
179→                Some(crate::git::types::UpstreamBranch {
180→                    name: upstream_name,
181→                    ahead: None,
182→                    behind: None,
183→                })
184→            });
185→
186→        Some(Branch {
187→            name,
188→            upstream,
189→            is_head: true,
190→            unix_timestamp: None,
191→        })
192→    }
193→
194→    fn branches(&self) -> GitResult<Vec<Branch>> {
195→        let repo = self.repository.lock().unwrap();
196→        let branches = repo.branches(None)?;
197→        let mut result = Vec::new();
198→
199→        for branch_result in branches {
200→            let (branch, _branch_type) = branch_result?;
201→            if let Some(name) = branch.name()? {
202→                let is_head = branch.is_head();
203→                result.push(Branch {
204→                    name: name.to_string(),
205→                    upstream: None,
206→                    is_head,
207→                    unix_timestamp: None,
208→                });
209→            }
210→        }
211→
212→        Ok(result)
213→    }
214→
215→    fn merge_base(&self, a: &str, b: &str) -> GitResult<Option<String>> {
216→        let repo = self.repository.lock().unwrap();
217→        let oid_a = match repo.revparse_single(a) {
218→            Ok(obj) => obj.id(),
219→            Err(_) => return Ok(None),
220→        };
221→        let oid_b = match repo.revparse_single(b) {
222→            Ok(obj) => obj.id(),
223→            Err(_) => return Ok(None),
224→        };
225→        match repo.merge_base(oid_a, oid_b) {
226→            Ok(oid) => Ok(Some(oid.to_string())),
227→            Err(_) => Ok(None),
228→        }
229→    }
230→
231→    fn remote_url(&self, name: &str) -> Option<String> {
232→        let repo = self.repository.lock().unwrap();
233→        repo.find_remote(name)
234→            .ok()
235→            .and_then(|r| r.url().map(|s| s.to_string()))
236→    }
237→
238→    // ── Diff / Content ─────────────────────────────────────
239→
240→    fn head_text_for_path(&self, path: &RepoPath) -> GitResult<Option<String>> {
241→        let repo = self.repository.lock().unwrap();
242→        let head = match repo.head() {
243→            Ok(h) => h,
244→            Err(_) => return Ok(None),
245→        };
246→        let tree = head.peel_to_tree()?;
247→        let entry = match tree.get_path(path.as_path()) {
248→            Ok(e) => e,
249→            Err(_) => return Ok(None),
250→        };
251→        let blob = repo.find_blob(entry.id())?;
252→        match std::str::from_utf8(blob.content()) {
253→            Ok(text) => Ok(Some(text.to_string())),
254→            Err(_) => Ok(None),
255→        }
256→    }
257→
258→    fn index_text_for_path(&self, path: &RepoPath) -> GitResult<Option<String>> {
259→        let repo = self.repository.lock().unwrap();
260→        let index = repo.index()?;
261→        let entry = match index.get_path(path.as_path(), 0) {
262→            Some(e) => e,
263→            None => return Ok(None),
264→        };
265→        let blob = repo.find_blob(entry.id)?;
266→        match std::str::from_utf8(blob.content()) {
267→            Ok(text) => Ok(Some(text.to_string())),
268→            Err(_) => Ok(None),
269→        }
270→    }
271→
272→    // ── Blame ──────────────────────────────────────────────
273→
274→    fn blame_for_path(
275→        &self,
276→        path: &RepoPath,
277→        _content: &str,
278→    ) -> GitResult<Vec<BlameEntry>> {
279→        let repo = self.repository.lock().unwrap();
280→        let blame = repo.blame_file(path.as_path(), None)?;
281→        let mut entries = Vec::new();
282→
283→        for i in 0..blame.len() {
284→            if let Some(hunk) = blame.get_index(i) {
285→                let sig = hunk.final_signature();
286→                entries.push(BlameEntry {
287→                    sha: hunk.final_commit_id().to_string(),
288→                    line_range: (hunk.final_start_line() as u32)
289→                        ..(hunk.final_start_line() as u32 + hunk.lines_in_hunk() as u32),
290→                    author: sig.name().map(|s| s.to_string()),
291→                    author_mail: sig.email().map(|s| s.to_string()),
292→                    author_timestamp: Some(sig.when().seconds()),
293→                    committer: None,
294→                    summary: None,
295→                });
296→            }
297→        }
298→
299→        Ok(entries)
300→    }
301→
302→    // ── Stash ──────────────────────────────────────────────
303→
304→    fn stash_list(&self) -> GitResult<Vec<StashEntry>> {
305→        let mut repo = self.repository.lock().unwrap();
306→        let mut entries = Vec::new();
307→        repo.stash_foreach(|index, message, oid| {
308→            entries.push(StashEntry {
309→                index,
310→                message: message.to_string(),
311→                sha: oid.to_string(),
312→            });
313→            true
314→        })?;
315→        Ok(entries)
316→    }
317→
318→    // ── History ────────────────────────────────────────────
319→
320→    fn log(
321→        &self,
322→        path: Option<&RepoPath>,
323→        limit: usize,
324→    ) -> GitResult<Vec<CommitSummary>> {
325→        let repo = self.repository.lock().unwrap();
326→        let mut revwalk = repo.revwalk()?;
327→        revwalk.set_sorting(git2::Sort::TIME)?;
328→        revwalk.push_head()?;
329→
330→        let mut results = Vec::new();
331→
332→        for oid_result in revwalk {
333→            if results.len() >= limit {
334→                break;
335→            }
336→            let oid = oid_result?;
337→            let commit = repo.find_commit(oid)?;
338→
339→            if let Some(filter_path) = path {
340→                let dominated = commit
341→                    .tree()
342→                    .ok()
343→                    .and_then(|t| t.get_path(filter_path.as_path()).ok())
344→                    .is_some();
345→                if !dominated {
346→                    continue;
347→                }
348→            }
349→
350→            let author = commit.author();
351→            results.push(CommitSummary {
352→                sha: oid.to_string(),
353→                message: commit.message().unwrap_or("").to_string(),
354→                author: author.name().unwrap_or("").to_string(),
355→                timestamp: author.when().seconds(),
356→            });
357→        }
358→
359→        Ok(results)
360→    }
361→
362→    fn show(&self, oid: &str) -> GitResult<CommitDetails> {
363→        let repo = self.repository.lock().unwrap();
364→        let obj = repo.revparse_single(oid)?;
365→        let commit = obj.peel_to_commit()?;
366→        let author = commit.author();
367→
368→        let summary = CommitSummary {
369→            sha: commit.id().to_string(),
370→            message: commit.message().unwrap_or("").to_string(),
371→            author: author.name().unwrap_or("").to_string(),
372→            timestamp: author.when().seconds(),
373→        };
374→
375→        let parent_shas = commit
376→            .parent_ids()
377→            .map(|id| id.to_string())
378→            .collect();
379→
380→        Ok(CommitDetails {
381→            summary,
382→            parent_shas,
383→            diff_stats: None,
384→        })
385→    }
386→
387→    fn reload_index(&self) {
388→        let repo = self.repository.lock().unwrap();
389→        if let Ok(mut index) = repo.index() {
390→            let _ = index.read(true);
391→        }
392→    }
393→
394→    // ── Mutating operations ────────────────────────────────
395→    // These use the git CLI or git2 index manipulation.
396→
397→    fn stage_paths(
398→        &self,
399→        paths: &[RepoPath],
400→        env: &HashMap<String, String>,
401→    ) -> GitResult<()> {
402→        if paths.is_empty() {
403→            return Ok(());
404→        }
405→        let mut args = vec!["add", "--"];
406→        let path_strings: Vec<String> = paths
407→            .iter()
408→            .map(|p| p.as_path().to_string_lossy().into_owned())
409→            .collect();
410→        for s in &path_strings {
411→            args.push(s);
412→        }
413→        self.run_git(&args, env)?;
414→        Ok(())
415→    }
416→
417→    fn unstage_paths(
418→        &self,
419→        paths: &[RepoPath],
420→        env: &HashMap<String, String>,
421→    ) -> GitResult<()> {
422→        if paths.is_empty() {
423→            return Ok(());
424→        }
425→        let mut args = vec!["reset", "HEAD", "--"];
426→        let path_strings: Vec<String> = paths
427→            .iter()
428→            .map(|p| p.as_path().to_string_lossy().into_owned())
429→            .collect();
430→        for s in &path_strings {
431→            args.push(s);
432→        }
433→        self.run_git(&args, env)?;
434→        Ok(())
435→    }
436→
437→    fn set_index_text(
438→        &self,
439→        path: &RepoPath,
440→        content: Option<String>,
441→        _env: &HashMap<String, String>,
442→    ) -> GitResult<()> {
443→        let repo = self.repository.lock().unwrap();
444→        let mut index = repo.index()?;
445→
446→        match content {
447→            Some(text) => {
448→                let oid = repo.blob(text.as_bytes())?;
449→                let entry = git2::IndexEntry {
450→                    ctime: git2::IndexTime::new(0, 0),
451→                    mtime: git2::IndexTime::new(0, 0),
452→                    dev: 0,
453→                    ino: 0,
454→                    mode: 0o100644,
455→                    uid: 0,
456→                    gid: 0,
457→                    file_size: text.len() as u32,
458→                    id: oid,
459→                    flags: 0,
460→                    flags_extended: 0,
461→                    path: path
462→                        .as_path()
463→                        .to_string_lossy()
464→                        .as_bytes()
465→                        .to_vec(),
466→                };
467→                index.add(&entry)?;
468→            }
469→            None => {
470→                index.remove_path(path.as_path())?;
471→            }
472→        }
473→
474→        index.write()?;
475→        Ok(())
476→    }
477→
478→    fn commit(
479→        &self,
480→        message: &str,
481→        options: &CommitOptions,
482→        env: &HashMap<String, String>,
483→    ) -> GitResult<()> {
484→        if options.amend {
485→            let mut args = vec!["commit", "--amend", "-m", message];
486→            if options.signoff {
487→                args.push("--signoff");
488→            }
489→            self.run_git(&args, env)?;
490→            return Ok(());
491→        }
492→
493→        let repo = self.repository.lock().unwrap();
494→        let mut index = repo.index()?;
495→        let tree_oid = index.write_tree()?;
496→        let tree = repo.find_tree(tree_oid)?;
497→        let sig = repo.signature()?;
498→
499→        let parents = match repo.head() {
500→            Ok(head) => {
501→                let parent = head.peel_to_commit()?;
502→                vec![parent]
503→            }
504→            Err(_) => vec![],
505→        };
506→        let parent_refs: Vec<&git2::Commit> = parents.iter().collect();
507→
508→        let mut msg = message.to_string();
509→        if options.signoff {
510→            msg.push_str(&format!(
511→                "\n\nSigned-off-by: {} <{}>",
512→                sig.name().unwrap_or(""),
513→                sig.email().unwrap_or("")
514→            ));
515→        }
516→
517→        repo.commit(Some("HEAD"), &sig, &sig, &msg, &tree, &parent_refs)?;
518→        Ok(())
519→    }
520→
521→    fn uncommit(&self, env: &HashMap<String, String>) -> GitResult<()> {
522→        self.run_git(&["reset", "HEAD^", "--soft"], env)?;
523→        Ok(())
524→    }
525→
526→    // ── Remote operations (CLI-based) ──────────────────────
527→
528→    fn push(
529→        &self,
530→        branch: &str,
531→        remote: Option<&str>,
532→        options: &PushOptions,
533→        env: &HashMap<String, String>,
534→    ) -> GitResult<()> {
535→        let remote_name = remote.unwrap_or("origin");
536→        let mut args = vec!["push", remote_name, branch];
537→        if options.force {
538→            args.push("--force");
539→        }
540→        if options.set_upstream {
541→            args.push("--set-upstream");
542→        }
543→        self.run_git(&args, env)?;
544→        Ok(())
545→    }
546→
547→    fn pull(
548→        &self,
549→        rebase: bool,
550→        env: &HashMap<String, String>,
551→    ) -> GitResult<()> {
552→        let mut args = vec!["pull"];
553→        if rebase {
554→            args.push("--rebase");
555→        }
556→        self.run_git(&args, env)?;
557→        Ok(())
558→    }
559→
560→    fn fetch(&self, env: &HashMap<String, String>) -> GitResult<()> {
561→        self.run_git(&["fetch"], env)?;
562→        Ok(())
563→    }
564→
565→    fn create_remote(&self, name: &str, url: &str) -> GitResult<()> {
566→        let repo = self.repository.lock().unwrap();
567→        repo.remote(name, url)?;
568→        Ok(())
569→    }
570→
571→    fn create_branch(&self, name: &str) -> GitResult<()> {
572→        let repo = self.repository.lock().unwrap();
573→        let head = repo.head()?;
574→        let commit = head.peel_to_commit()?;
575→        repo.branch(name, &commit, false)?;
576→        Ok(())
577→    }
578→
579→    fn checkout(&self, target: &str, env: &HashMap<String, String>) -> GitResult<()> {
580→        self.run_git(&["checkout", target], env)?;
581→        Ok(())
582→    }
583→
584→    fn delete_branch(&self, name: &str) -> GitResult<()> {
585→        let repo = self.repository.lock().unwrap();
586→        let mut branch = repo.find_branch(name, git2::BranchType::Local)?;
587→        branch.delete()?;
588→        Ok(())
589→    }
590→
591→    // ── Stash (CLI-based) ──────────────────────────────────
592→
593→    fn stash_all(&self, message: Option<&str>) -> GitResult<()> {
594→        let mut args = vec!["stash", "push"];
595→        if let Some(msg) = message {
596→            args.push("-m");
597→            args.push(msg);
598→        }
599→        self.run_git(&args, &HashMap::new())?;
600→        Ok(())
601→    }
602→
603→    fn stash_pop(&self, index: usize) -> GitResult<()> {
604→        let stash_ref = format!("stash@{{{index}}}");
605→        self.run_git(&["stash", "pop", &stash_ref], &HashMap::new())?;
606→        Ok(())
607→    }
608→
609→    fn stash_apply(&self, index: usize) -> GitResult<()> {
610→        let stash_ref = format!("stash@{{{index}}}");
611→        self.run_git(&["stash", "apply", &stash_ref], &HashMap::new())?;
612→        Ok(())
613→    }
614→
615→    fn stash_drop(&self, index: usize) -> GitResult<()> {
616→        let stash_ref = format!("stash@{{{index}}}");
617→        self.run_git(&["stash", "drop", &stash_ref], &HashMap::new())?;
618→        Ok(())
619→    }
620→
621→    // ── Conflict resolution ────────────────────────────────
622→
623→    fn checkout_conflict_path(
624→        &self,
625→        path: &RepoPath,
626→        side: ConflictSide,
627→    ) -> GitResult<()> {
628→        let side_flag = match side {
629→            ConflictSide::Ours => "--ours",
630→            ConflictSide::Theirs => "--theirs",
631→            ConflictSide::Base => {
632→                return Err(GitError::InvalidOperation(
633→                    "cannot checkout base side via CLI".to_string(),
634→                ));
635→            }
636→        };
637→        let path_str = path.as_path().to_string_lossy().to_string();
638→        self.run_git(
639→            &["checkout", side_flag, "--", &path_str],
640→            &HashMap::new(),
641→        )?;
642→        Ok(())
643→    }
644→}
