  1→use std::collections::HashMap;
  2→use std::sync::Arc;
  3→
  4→use gpui::{Context, EventEmitter, Task};
  5→use tokio::sync::mpsc;
  6→
  7→use crate::git::repository::GitRepository;
  8→use crate::git::types::{
  9→    Branch, CommitOptions, PushOptions, RepoPath, StagingState, StatusEntry,
 10→};
 11→
 12→// ---------------------------------------------------------------------------
 13→// RepositoryEvent
 14→// ---------------------------------------------------------------------------
 15→
 16→#[derive(Clone, Debug)]
 17→pub enum RepositoryEvent {
 18→    StatusChanged,
 19→    IndexChanged,
 20→    CommitCompleted { was_amend: bool },
 21→    BranchChanged,
 22→}
 23→
 24→// ---------------------------------------------------------------------------
 25→// PendingOp — optimistic UI state
 26→// ---------------------------------------------------------------------------
 27→
 28→#[derive(Clone, Copy, Debug, PartialEq, Eq)]
 29→pub enum PendingOp {
 30→    Staging,
 31→    Unstaging,
 32→}
 33→
 34→// ---------------------------------------------------------------------------
 35→// RepositorySnapshot — cheap clone for UI reads
 36→// ---------------------------------------------------------------------------
 37→
 38→#[derive(Clone, Debug, Default)]
 39→pub struct RepositorySnapshot {
 40→    pub branch: Option<Branch>,
 41→    pub stash_count: usize,
 42→}
 43→
 44→// ---------------------------------------------------------------------------
 45→// GitJob — job queue entries
 46→// ---------------------------------------------------------------------------
 47→
 48→enum GitJob {
 49→    RefreshStatus,
 50→    Stage {
 51→        paths: Vec<RepoPath>,
 52→    },
 53→    Unstage {
 54→        paths: Vec<RepoPath>,
 55→    },
 56→    SetIndexText {
 57→        path: RepoPath,
 58→        content: Option<String>,
 59→    },
 60→    Commit {
 61→        message: String,
 62→        options: CommitOptions,
 63→    },
 64→    Push {
 65→        branch: String,
 66→        remote: Option<String>,
 67→        options: PushOptions,
 68→    },
 69→    Pull {
 70→        rebase: bool,
 71→    },
 72→    Fetch,
 73→}
 74→
 75→// ---------------------------------------------------------------------------
 76→// Repository entity
 77→// ---------------------------------------------------------------------------
 78→
 79→pub struct Repository {
 80→    pub statuses: Vec<StatusEntry>,
 81→    pub snapshot: RepositorySnapshot,
 82→    pub pending_ops: HashMap<RepoPath, PendingOp>,
 83→
 84→    git_repo: Arc<dyn GitRepository>,
 85→    job_sender: mpsc::UnboundedSender<GitJob>,
 86→    _worker: Task<()>,
 87→}
 88→
 89→impl EventEmitter<RepositoryEvent> for Repository {}
 90→
 91→impl Repository {
 92→    pub fn new(
 93→        git_repo: Arc<dyn GitRepository>,
 94→        cx: &mut Context<Self>,
 95→    ) -> Self {
 96→        let (job_sender, mut job_receiver) = mpsc::unbounded_channel::<GitJob>();
 97→        let backend = git_repo.clone();
 98→
 99→        let worker = cx.spawn(async move |entity, cx| {
100→            while let Some(job) = job_receiver.recv().await {
101→                let backend = &backend;
102→                let env = HashMap::new();
103→
104→                match job {
105→                    GitJob::RefreshStatus => {
106→                        let entries = backend.status(&[]).unwrap_or_default();
107→                        let branch = backend.current_branch();
108→                        entity
109→                            .update(cx, |repo: &mut Repository, cx| {
110→                                repo.statuses = entries;
111→                                repo.snapshot.branch = branch;
112→                                cx.emit(RepositoryEvent::StatusChanged);
113→                                cx.notify();
114→                            })
115→                            .ok();
116→                    }
117→                    GitJob::Stage { paths } => {
118→                        let _result = backend.stage_paths(&paths, &env);
119→                        let entries = backend.status(&[]).unwrap_or_default();
120→                        entity
121→                            .update(cx, |repo: &mut Repository, cx| {
122→                                repo.statuses = entries;
123→                                for p in &paths {
124→                                    repo.pending_ops.remove(p);
125→                                }
126→                                cx.emit(RepositoryEvent::IndexChanged);
127→                                cx.notify();
128→                            })
129→                            .ok();
130→                    }
131→                    GitJob::Unstage { paths } => {
132→                        let _result = backend.unstage_paths(&paths, &env);
133→                        let entries = backend.status(&[]).unwrap_or_default();
134→                        entity
135→                            .update(cx, |repo: &mut Repository, cx| {
136→                                repo.statuses = entries;
137→                                for p in &paths {
138→                                    repo.pending_ops.remove(p);
139→                                }
140→                                cx.emit(RepositoryEvent::IndexChanged);
141→                                cx.notify();
142→                            })
143→                            .ok();
144→                    }
145→                    GitJob::SetIndexText { path, content } => {
146→                        let _result =
147→                            backend.set_index_text(&path, content, &env);
148→                        let entries = backend.status(&[]).unwrap_or_default();
149→                        entity
150→                            .update(cx, |repo: &mut Repository, cx| {
151→                                repo.statuses = entries;
152→                                cx.emit(RepositoryEvent::IndexChanged);
153→                                cx.notify();
154→                            })
155→                            .ok();
156→                    }
157→                    GitJob::Commit { message, options } => {
158→                        let was_amend = options.amend;
159→                        let _result =
160→                            backend.commit(&message, &options, &env);
161→                        let entries = backend.status(&[]).unwrap_or_default();
162→                        let branch = backend.current_branch();
163→                        entity
164→                            .update(cx, |repo: &mut Repository, cx| {
165→                                repo.statuses = entries;
166→                                repo.snapshot.branch = branch;
167→                                cx.emit(RepositoryEvent::CommitCompleted { was_amend });
168→                                cx.notify();
169→                            })
170→                            .ok();
171→                    }
172→                    GitJob::Push {
173→                        branch,
174→                        remote,
175→                        options,
176→                    } => {
177→                        let _result = backend.push(
178→                            &branch,
179→                            remote.as_deref(),
180→                            &options,
181→                            &env,
182→                        );
183→                    }
184→                    GitJob::Pull { rebase } => {
185→                        let _result = backend.pull(rebase, &env);
186→                        let entries = backend.status(&[]).unwrap_or_default();
187→                        let branch = backend.current_branch();
188→                        entity
189→                            .update(cx, |repo: &mut Repository, cx| {
190→                                repo.statuses = entries;
191→                                repo.snapshot.branch = branch;
192→                                cx.emit(RepositoryEvent::BranchChanged);
193→                                cx.notify();
194→                            })
195→                            .ok();
196→                    }
197→                    GitJob::Fetch => {
198→                        let _result = backend.fetch(&env);
199→                    }
200→                }
201→            }
202→        });
203→
204→        // Queue initial status refresh
205→        let _ = job_sender.send(GitJob::RefreshStatus);
206→
207→        Self {
208→            statuses: Vec::new(),
209→            snapshot: RepositorySnapshot::default(),
210→            pending_ops: HashMap::new(),
211→            git_repo,
212→            job_sender,
213→            _worker: worker,
214→        }
215→    }
216→
217→    /// Stage files with optimistic UI update.
218→    pub fn stage(&mut self, paths: Vec<RepoPath>, cx: &mut Context<Self>) {
219→        for path in &paths {
220→            self.pending_ops.insert(path.clone(), PendingOp::Staging);
221→        }
222→        cx.notify();
223→        let _ = self.job_sender.send(GitJob::Stage { paths });
224→    }
225→
226→    /// Unstage files with optimistic UI update.
227→    pub fn unstage(&mut self, paths: Vec<RepoPath>, cx: &mut Context<Self>) {
228→        for path in &paths {
229→            self.pending_ops.insert(path.clone(), PendingOp::Unstaging);
230→        }
231→        cx.notify();
232→        let _ = self.job_sender.send(GitJob::Unstage { paths });
233→    }
234→
235→    /// Write specific content to the index for a path.
236→    pub fn set_index_text(
237→        &mut self,
238→        path: RepoPath,
239→        content: Option<String>,
240→    ) {
241→        let _ = self
242→            .job_sender
243→            .send(GitJob::SetIndexText { path, content });
244→    }
245→
246→    /// Commit staged changes.
247→    pub fn commit(
248→        &mut self,
249→        message: String,
250→        options: CommitOptions,
251→        _cx: &mut Context<Self>,
252→    ) {
253→        let _ = self
254→            .job_sender
255→            .send(GitJob::Commit { message, options });
256→    }
257→
258→    /// Push to remote.
259→    pub fn push(
260→        &self,
261→        branch: String,
262→        remote: Option<String>,
263→        options: PushOptions,
264→    ) {
265→        let _ = self.job_sender.send(GitJob::Push {
266→            branch,
267→            remote,
268→            options,
269→        });
270→    }
271→
272→    /// Pull from remote.
273→    pub fn pull(&self, rebase: bool) {
274→        let _ = self.job_sender.send(GitJob::Pull { rebase });
275→    }
276→
277→    /// Fetch from remote.
278→    pub fn fetch(&self) {
279→        let _ = self.job_sender.send(GitJob::Fetch);
280→    }
281→
282→    /// Trigger a status refresh.
283→    pub fn refresh_status(&self) {
284→        let _ = self.job_sender.send(GitJob::RefreshStatus);
285→    }
286→
287→    /// Get the current snapshot for cheap UI reads.
288→    pub fn snapshot(&self) -> &RepositorySnapshot {
289→        &self.snapshot
290→    }
291→
292→    /// Get current status entries.
293→    pub fn statuses(&self) -> &[StatusEntry] {
294→        &self.statuses
295→    }
296→
297→    /// Get the effective staging state for a path, accounting for pending ops.
298→    pub fn effective_staging_state(&self, path: &RepoPath) -> StagingState {
299→        if let Some(pending) = self.pending_ops.get(path) {
300→            return match pending {
301→                PendingOp::Staging => StagingState::Staged,
302→                PendingOp::Unstaging => StagingState::Unstaged,
303→            };
304→        }
305→
306→        self.statuses
307→            .iter()
308→            .find(|s| &s.repo_path == path)
309→            .map(|s| s.staging_state())
310→            .unwrap_or(StagingState::Unstaged)
311→    }
312→
313→    /// Get the underlying git repository.
314→    pub fn git_repo(&self) -> &Arc<dyn GitRepository> {
315→        &self.git_repo
316→    }
317→}
318→

  1→use std::collections::HashMap;
  2→use std::sync::Arc;
  3→
  4→use gpui::{AppContext, Context, Entity, EventEmitter, Subscription};
  5→
  6→use crate::git::repository::GitRepository;
  7→use crate::git::repo_entity::{Repository, RepositoryEvent};
  8→
  9→// ---------------------------------------------------------------------------
 10→// RepositoryId
 11→// ---------------------------------------------------------------------------
 12→
 13→#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
 14→pub struct RepositoryId(u64);
 15→
 16→// ---------------------------------------------------------------------------
 17→// GitStoreEvent
 18→// ---------------------------------------------------------------------------
 19→
 20→#[derive(Clone, Debug)]
 21→pub enum GitStoreEvent {
 22→    ActiveRepositoryChanged,
 23→    StatusesChanged(RepositoryId),
 24→    CommitCompleted {
 25→        repository_id: RepositoryId,
 26→        was_amend: bool,
 27→    },
 28→    BranchChanged,
 29→}
 30→
 31→// ---------------------------------------------------------------------------
 32→// GitStore
 33→// ---------------------------------------------------------------------------
 34→
 35→pub struct GitStore {
 36→    repositories: HashMap<RepositoryId, Entity<Repository>>,
 37→    active_repository: Option<RepositoryId>,
 38→    next_repository_id: u64,
 39→    _subscriptions: Vec<Subscription>,
 40→}
 41→
 42→impl EventEmitter<GitStoreEvent> for GitStore {}
 43→
 44→impl GitStore {
 45→    pub fn new(_cx: &mut Context<Self>) -> Self {
 46→        Self {
 47→            repositories: HashMap::new(),
 48→            active_repository: None,
 49→            next_repository_id: 0,
 50→            _subscriptions: Vec::new(),
 51→        }
 52→    }
 53→
 54→    /// Add a repository to the store. Returns its ID.
 55→    /// Sets it as active if it's the first repository.
 56→    pub fn add_repository(
 57→        &mut self,
 58→        git_repo: Arc<dyn GitRepository>,
 59→        cx: &mut Context<Self>,
 60→    ) -> RepositoryId {
 61→        let id = RepositoryId(self.next_repository_id);
 62→        self.next_repository_id += 1;
 63→
 64→        let repo_entity = cx.new(|cx| Repository::new(git_repo, cx));
 65→
 66→        // Observe the Repository entity: when it notifies, re-emit
 67→        // StatusesChanged so the panel can react.
 68→        let observe_sub = cx.observe(&repo_entity, {
 69→            move |_this: &mut Self, _repo: Entity<Repository>, cx| {
 70→                cx.emit(GitStoreEvent::StatusesChanged(id));
 71→            }
 72→        });
 73→
 74→        // Subscribe to RepositoryEvent for commit/branch changes.
 75→        let event_sub = cx.subscribe(&repo_entity, {
 76→            move |_this: &mut Self, _repo: Entity<Repository>, event: &RepositoryEvent, cx| {
 77→                match event {
 78→                    RepositoryEvent::StatusChanged => {
 79→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 80→                    }
 81→                    RepositoryEvent::IndexChanged => {
 82→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 83→                    }
 84→                    RepositoryEvent::CommitCompleted { was_amend } => {
 85→                        cx.emit(GitStoreEvent::CommitCompleted {
 86→                            repository_id: id,
 87→                            was_amend: *was_amend,
 88→                        });
 89→                    }
 90→                    RepositoryEvent::BranchChanged => {
 91→                        cx.emit(GitStoreEvent::BranchChanged);
 92→                    }
 93→                }
 94→            }
 95→        });
 96→
 97→        self._subscriptions.push(observe_sub);
 98→        self._subscriptions.push(event_sub);
 99→        self.repositories.insert(id, repo_entity);
100→
101→        // First repository becomes active
102→        if self.active_repository.is_none() {
103→            self.active_repository = Some(id);
104→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
105→        }
106→
107→        id
108→    }
109→
110→    /// Remove a repository from the store.
111→    pub fn remove_repository(
112→        &mut self,
113→        id: RepositoryId,
114→        cx: &mut Context<Self>,
115→    ) {
116→        self.repositories.remove(&id);
117→
118→        if self.active_repository == Some(id) {
119→            // Pick another repository or None
120→            self.active_repository = self.repositories.keys().next().copied();
121→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
122→        }
123→    }
124→
125→    /// Get the active repository entity.
126→    pub fn active_repository(&self) -> Option<&Entity<Repository>> {
127→        self.active_repository
128→            .and_then(|id| self.repositories.get(&id))
129→    }
130→
131→    /// Get the active repository ID.
132→    pub fn active_repository_id(&self) -> Option<RepositoryId> {
133→        self.active_repository
134→    }
135→
136→    /// Set the active repository by ID.
137→    pub fn set_active_repository(
138→        &mut self,
139→        id: RepositoryId,
140→        cx: &mut Context<Self>,
141→    ) {
142→        if self.repositories.contains_key(&id) && self.active_repository != Some(id) {
143→            self.active_repository = Some(id);
144→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
145→        }
146→    }
147→
148→    /// Get a repository by ID.
149→    pub fn repository(&self, id: RepositoryId) -> Option<&Entity<Repository>> {
150→        self.repositories.get(&id)
151→    }
152→
153→    /// Iterate all repositories.
154→    pub fn repositories(
155→        &self,
156→    ) -> impl Iterator<Item = (RepositoryId, &Entity<Repository>)> {
157→        self.repositories.iter().map(|(id, repo)| (*id, repo))
158→    }
159→
160→    /// Number of tracked repositories.
161→    pub fn repository_count(&self) -> usize {
162→        self.repositories.len()
163→    }
164→}
