 13→impl RepoPath {
 14→    pub fn new(path: impl Into<PathBuf>) -> Self {
 15→        Self(Arc::from(path.into()))
 16→    }
 17→
 18→    pub fn as_path(&self) -> &Path {
 19→        &self.0
 20→    }
 21→}
 22→
 23→impl PartialOrd for RepoPath {
 24→    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
 25→        Some(self.cmp(other))
 26→    }
 27→}
