 13→/// Git repository backed by git2 for local operations and the git CLI for
 14→/// network operations.
 15→pub struct RealGitRepository {
 16→    repository: Mutex<git2::Repository>,
 17→    path: PathBuf,
 18→    work_directory: Option<PathBuf>,
 19→}
 20→
 21→impl RealGitRepository {
 22→    pub fn open(path: &Path) -> GitResult<Self> {
 23→        let repo = git2::Repository::open(path)?;
 24→        let git_path = repo.path().to_path_buf();
 25→        let work_dir = repo.workdir().map(|p| p.to_path_buf());
 26→        Ok(Self {
 27→            repository: Mutex::new(repo),
 28→            path: git_path,
 29→            work_directory: work_dir,
 30→        })
 31→    }
 32→
 33→    pub fn discover(path: &Path) -> GitResult<Self> {
 34→        let repo = git2::Repository::discover(path)?;
 35→        let git_path = repo.path().to_path_buf();
 36→        let work_dir = repo.workdir().map(|p| p.to_path_buf());
 37→        Ok(Self {
 38→            repository: Mutex::new(repo),
 39→            path: git_path,
 40→            work_directory: work_dir,
 41→        })
 42→    }
 43→
 44→    fn run_git(
 45→        &self,
 46→        args: &[&str],
 47→        env: &HashMap<String, String>,
 48→    ) -> GitResult<String> {
 49→        let cwd = self
 50→            .work_directory
 51→            .as_deref()
 52→            .unwrap_or(&self.path);
 53→
 54→        let output = Command::new("git")
 55→            .args(args)
 56→            .envs(env)
 57→            .current_dir(cwd)
 58→            .output()?;
 59→
 60→        if output.status.success() {
 61→            Ok(String::from_utf8_lossy(&output.stdout).into_owned())
 62→        } else {
 63→            Err(GitError::CliError {
 64→                exit_code: output.status.code().unwrap_or(-1),
 65→                stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
 66→            })
 67→        }
 68→    }
 69→
 70→    fn map_git2_status(status: git2::Status) -> GitFileStatus {
 71→        let index_status = if status.contains(git2::Status::INDEX_NEW) {
 72→            FileStatus::Added
 73→        } else if status.contains(git2::Status::INDEX_MODIFIED)
 74→            || status.contains(git2::Status::INDEX_RENAMED)
 75→            || status.contains(git2::Status::INDEX_TYPECHANGE)
 76→        {
 77→            FileStatus::Modified
 78→        } else if status.contains(git2::Status::INDEX_DELETED) {
 79→            FileStatus::Deleted
 80→        } else {
 81→            FileStatus::Unchanged
 82→        };
 83→
 84→        let worktree_status = if status.contains(git2::Status::WT_NEW) {
 85→            FileStatus::Untracked
 86→        } else if status.contains(git2::Status::WT_MODIFIED)
 87→            || status.contains(git2::Status::WT_RENAMED)
 88→            || status.contains(git2::Status::WT_TYPECHANGE)
 89→        {
 90→            FileStatus::Modified
 91→        } else if status.contains(git2::Status::WT_DELETED) {
 92→            FileStatus::Deleted
 93→        } else {
 94→            FileStatus::Unchanged
 95→        };
 96→
 97→        let conflict = status.contains(git2::Status::CONFLICTED);
 98→
 99→        GitFileStatus {
100→            index_status,
101→            worktree_status,
102→            conflict,
103→        }
104→    }
105→}
