144→impl GitRepository for FakeGitRepository {
145→    fn path(&self) -> &Path {
146→        &self.path
147→    }
148→
149→    fn work_directory(&self) -> Option<&Path> {
150→        self.work_directory.as_deref()
151→    }
152→
153→    fn status(&self, _path_prefixes: &[RepoPath]) -> GitResult<Vec<StatusEntry>> {
154→        let head = self.head.lock().unwrap();
155→        let index = self.index.lock().unwrap();
156→        let worktree = self.worktree.lock().unwrap();
157→
158→        // Collect all known paths
159→        let mut all_paths: Vec<RepoPath> = head
160→            .keys()
161→            .chain(index.keys())
162→            .chain(worktree.keys())
163→            .cloned()
164→            .collect();
165→        all_paths.sort();
166→        all_paths.dedup();
167→
168→        let mut entries = Vec::new();
169→        for path in all_paths {
170→            if let Some(status) = self.derive_status_for(&path, &head, &index, &worktree) {
171→                entries.push(StatusEntry {
172→                    repo_path: path,
173→                    status,
174→                });
175→            }
176→        }
177→
178→        Ok(entries)
179→    }
180→
181→    fn status_for_path(&self, path: &RepoPath) -> GitResult<Option<StatusEntry>> {
182→        let head = self.head.lock().unwrap();
183→        let index = self.index.lock().unwrap();
184→        let worktree = self.worktree.lock().unwrap();
185→
186→        Ok(self
187→            .derive_status_for(path, &head, &index, &worktree)
188→            .map(|status| StatusEntry {
189→                repo_path: path.clone(),
190→                status,
191→            }))
192→    }
193→
194→    fn stage_paths(
195→        &self,
196→        paths: &[RepoPath],
197→        _env: &HashMap<String, String>,
198→    ) -> GitResult<()> {
199→        let mut index = self.index.lock().unwrap();
200→        let worktree = self.worktree.lock().unwrap();
201→
202→        for path in paths {
203→            if let Some(content) = worktree.get(path) {
204→                index.insert(path.clone(), content.clone());
205→            } else {
206→                // File deleted in worktree — remove from index
207→                index.remove(path);
208→            }
209→        }
210→
211→        Ok(())
212→    }
213→
214→    fn unstage_paths(
215→        &self,
216→        paths: &[RepoPath],
217→        _env: &HashMap<String, String>,
218→    ) -> GitResult<()> {
219→        let head = self.head.lock().unwrap();
220→        let mut index = self.index.lock().unwrap();
221→
222→        for path in paths {
223→            if let Some(content) = head.get(path) {
224→                index.insert(path.clone(), content.clone());
225→            } else {
226→                index.remove(path);
227→            }
228→        }
229→
230→        Ok(())
231→    }
232→
233→    fn set_index_text(
234→        &self,
235→        path: &RepoPath,
236→        content: Option<String>,
237→        _env: &HashMap<String, String>,
238→    ) -> GitResult<()> {
239→        let mut index = self.index.lock().unwrap();
240→        match content {
241→            Some(text) => {
242→                index.insert(path.clone(), text);
243→            }
244→            None => {
245→                index.remove(path);
246→            }
247→        }
248→        Ok(())
249→    }
250→
251→    fn reload_index(&self) {
252→        // No-op for fake
253→    }
254→
255→    fn commit(
256→        &self,
257→        message: &str,
258→        _options: &CommitOptions,
259→        _env: &HashMap<String, String>,
260→    ) -> GitResult<()> {
261→        let index = self.index.lock().unwrap();
262→        let mut head = self.head.lock().unwrap();
263→
264→        // Copy index state to head
265→        *head = index.clone();
266→
267→        // Record commit
268→        let mut commits = self.commits.lock().unwrap();
269→        let sha = format!("fake-{}", commits.len());
270→        commits.push(CommitSummary {
271→            sha,
272→            message: message.to_string(),
273→            author: "Test User".to_string(),
274→            timestamp: 0,
275→        });
276→
277→        Ok(())
278→    }
279→
280→    fn uncommit(&self, _env: &HashMap<String, String>) -> GitResult<()> {
281→        let mut commits = self.commits.lock().unwrap();
282→        if commits.is_empty() {
283→            return Err(GitError::InvalidOperation(
284→                "no commits to undo".to_string(),
285→            ));
286→        }
287→        commits.pop();
288→        Ok(())
289→    }
290→
