  1→use gpui::{
  2→    div, Context, Entity, FocusHandle, InteractiveElement, IntoElement, ParentElement, Render,
  3→    StatefulInteractiveElement, Styled, Subscription, Window,
  4→};
  5→
  6→use crate::actions::{
  7→    Commit, SelectNext, SelectPrev, StageAll, ToggleStaging, UnstageAll,
  8→};
  9→use crate::git::store::{GitStore, GitStoreEvent};
 10→use crate::git::types::{CommitOptions, FileStatus, RepoPath, StagingState, StatusEntry};
 11→use crate::theme::Theme;
 12→
 13→// ---------------------------------------------------------------------------
 14→// Entry — a file in the staged or unstaged section
 15→// ---------------------------------------------------------------------------
 16→
 17→#[derive(Clone, Debug)]
 18→struct PanelEntry {
 19→    status_entry: StatusEntry,
 20→    staged: bool,
 21→}
 22→
 23→// ---------------------------------------------------------------------------
 24→// GitPanel
 25→// ---------------------------------------------------------------------------
 26→
 27→pub struct GitPanel {
 28→    git_store: Entity<GitStore>,
 29→    entries: Vec<PanelEntry>,
 30→    selected_index: Option<usize>,
 31→    commit_message: String,
 32→    focus_handle: FocusHandle,
 33→    _subscriptions: Vec<Subscription>,
 34→}
 35→
 36→impl GitPanel {
 37→    pub fn new(
 38→        git_store: Entity<GitStore>,
 39→        cx: &mut Context<Self>,
 40→    ) -> Self {
 41→        let focus_handle = cx.focus_handle();
 42→
 43→        let sub = cx.subscribe(&git_store, |this: &mut Self, _store, event, cx| {
 44→            match event {
 45→                GitStoreEvent::StatusesChanged(_)
 46→                | GitStoreEvent::ActiveRepositoryChanged
 47→                | GitStoreEvent::BranchChanged => {
 48→                    this.rebuild_entries(cx);
 49→                    cx.notify();
 50→                }
 51→                GitStoreEvent::CommitCompleted { .. } => {
 52→                    this.commit_message.clear();
 53→                    this.rebuild_entries(cx);
 54→                    cx.notify();
 55→                }
 56→            }
 57→        });
 58→
 59→        let mut panel = Self {
 60→            git_store,
 61→            entries: Vec::new(),
 62→            selected_index: None,
 63→            commit_message: String::new(),
 64→            focus_handle,
 65→            _subscriptions: vec![sub],
 66→        };
 67→
 68→        panel.rebuild_entries(cx);
 69→        panel
 70→    }
 71→
 72→    fn rebuild_entries(&mut self, cx: &mut Context<Self>) {
 73→        self.entries.clear();
 74→
 75→        let store = self.git_store.read(cx);
 76→        let Some(repo_entity) = store.active_repository() else {
 77→            return;
 78→        };
 79→
 80→        let repo = repo_entity.read(cx);
 81→
 82→        for entry in repo.statuses() {
 83→            let effective = repo.effective_staging_state(&entry.repo_path);
 84→            match effective {
 85→                StagingState::Staged => {
 86→                    self.entries.push(PanelEntry {
 87→                        status_entry: entry.clone(),
 88→                        staged: true,
 89→                    });
 90→                }
 91→                StagingState::Unstaged => {
 92→                    self.entries.push(PanelEntry {
 93→                        status_entry: entry.clone(),
 94→                        staged: false,
 95→                    });
 96→                }
 97→                StagingState::PartiallyStaged => {
 98→                    self.entries.push(PanelEntry {
 99→                        status_entry: entry.clone(),
100→                        staged: true,
101→                    });
102→                    self.entries.push(PanelEntry {
103→                        status_entry: entry.clone(),
104→                        staged: false,
105→                    });
106→                }
107→            }
108→        }
109→
110→        // Sort: staged first, then unstaged; within each group, by path
111→        self.entries.sort_by(|a, b| {
112→            b.staged
113→                .cmp(&a.staged)
114→                .then_with(|| a.status_entry.repo_path.cmp(&b.status_entry.repo_path))
115→        });
116→
117→        // Clamp selection
118→        if let Some(idx) = self.selected_index {
119→            if idx >= self.entries.len() {
120→                self.selected_index = if self.entries.is_empty() {
121→                    None
122→                } else {
123→                    Some(self.entries.len() - 1)
124→                };
125→            }
126→        }
127→    }
128→
129→    fn staged_entries(&self) -> Vec<&PanelEntry> {
130→        self.entries.iter().filter(|e| e.staged).collect()
131→    }
132→
133→    fn unstaged_entries(&self) -> Vec<&PanelEntry> {
134→        self.entries.iter().filter(|e| !e.staged).collect()
135→    }
136→
137→    fn toggle_staging_for(
138→        &mut self,
139→        path: RepoPath,
140→        currently_staged: bool,
141→        cx: &mut Context<Self>,
142→    ) {
143→        let store = self.git_store.read(cx);
144→        let Some(repo_entity) = store.active_repository().cloned() else {
145→            return;
146→        };
147→
148→        if currently_staged {
149→            repo_entity.update(cx, |repo, cx| {
150→                repo.unstage(vec![path], cx);
151→            });
152→        } else {
153→            repo_entity.update(cx, |repo, cx| {
154→                repo.stage(vec![path], cx);
155→            });
156→        }
157→    }
158→
159→    fn stage_all(&mut self, cx: &mut Context<Self>) {
160→        let paths: Vec<RepoPath> = self
161→            .unstaged_entries()
162→            .iter()
163→            .map(|e| e.status_entry.repo_path.clone())
164→            .collect();
165→
166→        if paths.is_empty() {
167→            return;
168→        }
169→
170→        let store = self.git_store.read(cx);
171→        let Some(repo_entity) = store.active_repository().cloned() else {
172→            return;
173→        };
174→
175→        repo_entity.update(cx, |repo, cx| {
176→            repo.stage(paths, cx);
177→        });
178→    }
179→
180→    fn unstage_all(&mut self, cx: &mut Context<Self>) {
181→        let paths: Vec<RepoPath> = self
182→            .staged_entries()
183→            .iter()
184→            .map(|e| e.status_entry.repo_path.clone())
185→            .collect();
186→
187→        if paths.is_empty() {
188→            return;
189→        }
190→
191→        let store = self.git_store.read(cx);
192→        let Some(repo_entity) = store.active_repository().cloned() else {
193→            return;
194→        };
195→
196→        repo_entity.update(cx, |repo, cx| {
197→            repo.unstage(paths, cx);
198→        });
199→    }
200→
201→    fn toggle_selected(&mut self, cx: &mut Context<Self>) {
202→        let Some(idx) = self.selected_index else {
203→            return;
204→        };
205→        let Some(entry) = self.entries.get(idx) else {
206→            return;
207→        };
208→        let path = entry.status_entry.repo_path.clone();
209→        let staged = entry.staged;
210→        self.toggle_staging_for(path, staged, cx);
211→    }
212→
213→    fn do_commit(&mut self, cx: &mut Context<Self>) {
214→        let message = self.commit_message.trim().to_string();
215→        if message.is_empty() {
216→            return;
217→        }
218→
219→        let store = self.git_store.read(cx);
220→        let Some(repo_entity) = store.active_repository().cloned() else {
221→            return;
222→        };
223→
224→        repo_entity.update(cx, |repo, cx| {
225→            repo.commit(message, CommitOptions::default(), cx);
226→        });
227→    }
228→
229→    fn select_next(&mut self, cx: &mut Context<Self>) {
230→        if self.entries.is_empty() {
231→            return;
232→        }
233→        self.selected_index = Some(match self.selected_index {
234→            None => 0,
235→            Some(idx) => (idx + 1).min(self.entries.len() - 1),
236→        });
237→        cx.notify();
238→    }
239→
240→    fn select_prev(&mut self, cx: &mut Context<Self>) {
241→        if self.entries.is_empty() {
242→            return;
243→        }
244→        self.selected_index = Some(match self.selected_index {
245→            None => 0,
246→            Some(idx) => idx.saturating_sub(1),
247→        });
248→        cx.notify();
249→    }
250→
251→    fn handle_key_down(
252→        &mut self,
253→        event: &gpui::KeyDownEvent,
254→        _window: &mut Window,
255→        cx: &mut Context<Self>,
256→    ) {
257→        let key_char = event.keystroke.key_char.as_deref();
258→        match key_char {
259→            Some(ch) if !event.keystroke.modifiers.platform
260→                && !event.keystroke.modifiers.control =>
261→            {
262→                self.commit_message.push_str(ch);
263→                cx.notify();
264→            }
265→            _ => {
266→                // Handle special keys by key name
267→                match event.keystroke.key.as_str() {
268→                    "backspace" if !event.keystroke.modifiers.platform => {
269→                        self.commit_message.pop();
270→                        cx.notify();
271→                    }
272→                    _ => {}
273→                }
274→            }
275→        }
276→    }
277→}
