  1→use std::collections::HashMap;
  2→use std::sync::Arc;
  3→
  4→use gpui::{AppContext, Context, Entity, EventEmitter, Subscription};
  5→
  6→use crate::git::repository::GitRepository;
  7→use crate::git::repo_entity::{Repository, RepositoryEvent};
  8→
  9→// ---------------------------------------------------------------------------
 10→// RepositoryId
 11→// ---------------------------------------------------------------------------
 12→
 13→#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
 14→pub struct RepositoryId(u64);
 15→
 16→// ---------------------------------------------------------------------------
 17→// GitStoreEvent
 18→// ---------------------------------------------------------------------------
 19→
 20→#[derive(Clone, Debug)]
 21→pub enum GitStoreEvent {
 22→    ActiveRepositoryChanged,
 23→    StatusesChanged(RepositoryId),
 24→    CommitCompleted {
 25→        repository_id: RepositoryId,
 26→        was_amend: bool,
 27→    },
 28→    BranchChanged,
 29→}
 30→
 31→// ---------------------------------------------------------------------------
 32→// GitStore
 33→// ---------------------------------------------------------------------------
 34→
 35→pub struct GitStore {
 36→    repositories: HashMap<RepositoryId, Entity<Repository>>,
 37→    active_repository: Option<RepositoryId>,
 38→    next_repository_id: u64,
 39→    _subscriptions: Vec<Subscription>,
 40→}
 41→
 42→impl EventEmitter<GitStoreEvent> for GitStore {}
 43→
 44→impl GitStore {
 45→    pub fn new(_cx: &mut Context<Self>) -> Self {
 46→        Self {
 47→            repositories: HashMap::new(),
 48→            active_repository: None,
 49→            next_repository_id: 0,
 50→            _subscriptions: Vec::new(),
 51→        }
 52→    }
 53→
 54→    /// Add a repository to the store. Returns its ID.
 55→    /// Sets it as active if it's the first repository.
 56→    pub fn add_repository(
 57→        &mut self,
 58→        git_repo: Arc<dyn GitRepository>,
 59→        cx: &mut Context<Self>,
 60→    ) -> RepositoryId {
 61→        let id = RepositoryId(self.next_repository_id);
 62→        self.next_repository_id += 1;
 63→
 64→        let repo_entity = cx.new(|cx| Repository::new(git_repo, cx));
 65→
 66→        // Subscribe to RepositoryEvent for all state changes.
 67→        // No separate observe() needed — the subscribe handler covers all events.
 68→        let event_sub = cx.subscribe(&repo_entity, {
 69→            move |_this: &mut Self, _repo: Entity<Repository>, event: &RepositoryEvent, cx| {
 70→                match event {
 71→                    RepositoryEvent::StatusChanged => {
 72→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 73→                    }
 74→                    RepositoryEvent::IndexChanged => {
 75→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 76→                    }
 77→                    RepositoryEvent::CommitCompleted { was_amend } => {
 78→                        cx.emit(GitStoreEvent::CommitCompleted {
 79→                            repository_id: id,
 80→                            was_amend: *was_amend,
 81→                        });
 82→                    }
 83→                    RepositoryEvent::BranchChanged => {
 84→                        cx.emit(GitStoreEvent::BranchChanged);
 85→                    }
 86→                }
 87→            }
 88→        });
 89→
 90→        self._subscriptions.push(event_sub);
 91→        self.repositories.insert(id, repo_entity);
 92→
 93→        // First repository becomes active
 94→        if self.active_repository.is_none() {
 95→            self.active_repository = Some(id);
 96→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
 97→        }
 98→
 99→        id
100→    }
101→
102→    /// Remove a repository from the store.
103→    pub fn remove_repository(
104→        &mut self,
105→        id: RepositoryId,
106→        cx: &mut Context<Self>,
107→    ) {
108→        self.repositories.remove(&id);
109→
110→        if self.active_repository == Some(id) {
111→            // Pick another repository or None
112→            self.active_repository = self.repositories.keys().next().copied();
113→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
114→        }
115→    }
116→
117→    /// Get the active repository entity.
118→    pub fn active_repository(&self) -> Option<&Entity<Repository>> {
119→        self.active_repository
120→            .and_then(|id| self.repositories.get(&id))
121→    }
122→
123→    /// Get the active repository ID.
124→    pub fn active_repository_id(&self) -> Option<RepositoryId> {
125→        self.active_repository
126→    }
127→
128→    /// Set the active repository by ID.
129→    pub fn set_active_repository(
130→        &mut self,
131→        id: RepositoryId,
132→        cx: &mut Context<Self>,
133→    ) {
134→        if self.repositories.contains_key(&id) && self.active_repository != Some(id) {
135→            self.active_repository = Some(id);
136→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
137→        }
138→    }
139→
140→    /// Get a repository by ID.
141→    pub fn repository(&self, id: RepositoryId) -> Option<&Entity<Repository>> {
142→        self.repositories.get(&id)
143→    }
144→
145→    /// Iterate all repositories.
146→    pub fn repositories(
147→        &self,
148→    ) -> impl Iterator<Item = (RepositoryId, &Entity<Repository>)> {
